const taskResponses = $input.all();
const courses = $('2. Separar Cursos').all();
const courseMap = new Map(
  courses.map(item => [String(item.json.courseId), item.json])
);

const output = [];

for (const response of taskResponses) {
  for (const task of response.json.courseWork ?? []) {
    const course = courseMap.get(String(task.courseId));

    output.push({
      json: {
        platform: 'google_classroom',
        courseId: task.courseId,
        courseName: course?.courseName ?? '',
        courseSection: course?.courseSection ?? '',
        teacherFolderId: course?.teacherFolderId ?? null,
        teacherFolderName: course?.teacherFolderName ?? null,

        assignmentId: task.id,
        assignmentTitle: task.title,
        assignmentDescription: task.description ?? '',
        assignmentState: task.state,
        assignmentType: task.workType,
        maxPoints: task.maxPoints ?? null,
        creationTime: task.creationTime ?? null,
        updateTime: task.updateTime ?? null,
        dueDate: task.dueDate ?? null,
        dueTime: task.dueTime ?? null,
        assignmentAlternateLink: task.alternateLink ?? null,
        rawAssignment: task,
      },
    });
  }
}

return output;

const resultado = [];

for (const item of $input.all()) {
  const entregas = item.json.studentSubmissions ?? [];

  for (const entrega of entregas) {
    if (entrega.state !== 'TURNED_IN') continue;

    const attachments = entrega.assignmentSubmission?.attachments ?? [];

    resultado.push({
      json: {
        platform: 'google_classroom',
        courseId: entrega.courseId,
        assignmentId: entrega.courseWorkId,
        submissionId: entrega.id,
        studentId: entrega.userId,
        submissionCreatedAt: entrega.creationTime ?? null,
        submissionUpdatedAt: entrega.updateTime ?? null,
        submissionState: entrega.state,
        attachments,
        hasAttachments: attachments.length > 0,
        rawSubmission: entrega,
      },
    });
  }
}

return resultado;

const entrega = $json;

const archivo = entrega.attachments?.[0]?.driveFile ?? {};

return {
  json: {
    ...entrega,

    evaluationKey: `${entrega.courseId}_${entrega.assignmentId}_${entrega.studentId}`,

    fileId: archivo.id ?? '',
    fileName: archivo.title ?? '',
    fileLink: archivo.alternateLink ?? '',
    fileThumbnailUrl: archivo.thumbnailUrl ?? '',

    hasFile: !!archivo.id,
    fileSource: 'google_drive',
