studentId: meta.studentId,
courseId: meta.courseId,
assignmentId: meta.assignmentId,
  }
};

const original = $('15. Unir Texto + Datos').item.json;

return {
  json: {
    ...original,
    estudianteNombre: $json.name?.fullName || '',
    estudianteNombreObjeto: $json.name || null,
    classroomProfileId: $json.id,
  }
};

const texto = $json.output[0].content[0].text;

const limpio = texto
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

try {
  const resultado = JSON.parse(limpio);

  return {
    json: {
      ...$json,
      tipo_tarea: resultado.tipo_tarea,
      calificacion: resultado.calificacion,
      fortalezas: resultado.fortalezas,
      aspectos_mejorar: resultado.aspectos_mejorar,
      retroalimentacion: resultado.retroalimentacion,
      errorProcesandoIA: false,
    }
  };
} catch (error) {
  return {
    json: {
      ...$json,
      errorProcesandoIA: true,
      rawRespuestaIA: texto,
      mensajeError: error.message,
    }
  };
}

const items = $input.all();

const limpiarNombreArchivo = (texto) =>
  String(texto || "Reporte iDoceo")
    .replace(/[\\/:*?"<>|]/g, "")
    .replace(/\s+/g, " ")
    .trim();

const grupos = {};

for (const item of items) {
  const data = item.json;

  const assignmentId =
    data.assignmentId ||
    data.nombreArchivo ||
    data.assignmentTitle ||
    "sin_tarea";

  const nombreArchivo = limpiarNombreArchivo(
    data.assignmentTitle ||
    data.nombreArchivo ||
    data.tareaNombre ||
    "Reporte iDoceo"
  );

  const teacherFolderId =
    data.teacherFolderId ||
    data.courseFolderId ||
    data.teacherFolder?.id ||
    data.carpetaCursoId ||
    data["Carpeta del profesor"]?.identificación ||
    data["Carpeta del profesor"]?.id ||
    "";

  const teacherFolderName =
    data.teacherFolderName ||
    data.courseFolderName ||
