const data = $json;

const tituloTarea =
  data.tituloTarea ||
  data.assignmentTitle ||
  data.assignmentName ||
  data.title ||
  '';

const textoBase = `${tituloTarea} ${data.courseName || ''} ${data.materia || ''}`.toLowerCase();

let area = data.area || data.materia || '';
let mencion = data.mencion || 'Para todos';
let tipoTarea = data.tipoTarea || '';
let grado = data.grado || data.courseSection || data.courseName || 'Todos';

if (!tipoTarea) {
  if (textoBase.includes('investig')) tipoTarea = 'Investigacion';
  else if (textoBase.includes('cuestionario')) tipoTarea = 'Cuestionario';
  else if (textoBase.includes('glosario')) tipoTarea = 'Glosario de terminos';
  else if (textoBase.includes('ensayo')) tipoTarea = 'Ensayo';
  else if (textoBase.includes('resumen')) tipoTarea = 'Resumen';
  else if (textoBase.includes('ejercicio')) tipoTarea = 'Ejercicios';
  else if (textoBase.includes('proyecto')) tipoTarea = 'Proyecto';
  else tipoTarea = 'Tarea escrita';
}

if (!area) {
  if (textoBase.includes('matemat')) area = 'Matematica';
  else if (textoBase.includes('lengua')) area = 'Lengua Espanola';
  else if (textoBase.includes('sociales')) area = 'Ciencias Sociales';
  else if (textoBase.includes('naturales')) area = 'Ciencias de la Naturaleza';
  else if (textoBase.includes('ingles')) area = 'Ingles';
  else if (textoBase.includes('frances')) area = 'Frances';
  else if (textoBase.includes('arte')) area = 'Artes';
  else area = 'Para todos';
}

if (area === 'Artes' && mencion === 'Para todos') {
  if (textoBase.includes('multimedia')) mencion = 'Arte Multimedia';
  else if (textoBase.includes('visual')) mencion = 'Artes Visuales';
  else if (textoBase.includes('cine') || textoBase.includes('fotografia')) mencion = 'Cine y Fotografia';
  else if (textoBase.includes('danza')) mencion = 'Danza';
  else if (textoBase.includes('musica')) mencion = 'Musica';
  else if (textoBase.includes('teatro')) mencion = 'Teatro';
  else if (textoBase.includes('artesanal') || textoBase.includes('ceramica')) {
    mencion = 'Creacion y Produccion Artistica Artesanal';
  }
}

return {
  json: {
