  },
};

const entregas = $('17a. Identificar Datos de Rúbrica').all().map(item => item.json);
const rubricas = $input.all().map(item => item.json);

function normalizar(valor) {
  return String(valor || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

function crearGrupo(entrega) {
  const profesor =
    entrega.teacherName ||
    entrega.docenteNombre ||
    entrega.teacherFolderName ||
    'Profesor no identificado';

  const curso =
    entrega.courseName ||
    entrega.curso ||
    entrega.courseSection ||
    'Curso no identificado';

  const area =
    entrega.area ||
    entrega.materia ||
    'Area no identificada';

  const mencion =
    entrega.mencion ||
    'Para todos';

  const tarea =
    entrega.tituloTarea ||
    entrega.assignmentTitle ||
    entrega.assignmentName ||
    entrega.title ||
    'Tarea sin nombre';

  return `${profesor} | ${curso} | ${area} | ${mencion} | ${tarea}`
    .replace(/[\\/:*?"<>|]/g, '-')
    .trim();
}

function buscarRubrica(entrega) {
  const area = normalizar(entrega.area);
  const mencion = normalizar(entrega.mencion);
  const tipoTarea = normalizar(entrega.tipoTarea);
  const grado = normalizar(entrega.grado);

  const activa = r => normalizar(r.activa) === 'si';

  let matchTipo = 'exacta';

  let rubrica =
    rubricas.find(r =>
      activa(r) &&
      normalizar(r.area) === area &&
      normalizar(r.mencion) === mencion &&
      normalizar(r.tipoTarea) === tipoTarea &&
      normalizar(r.grado) === grado
    );

  if (!rubrica) {
    matchTipo = 'sin_grado';
    rubrica = rubricas.find(r =>
      activa(r) &&
      normalizar(r.area) === area &&
      normalizar(r.mencion) === mencion &&
      normalizar(r.tipoTarea) === tipoTarea
    );
  }

  if (!rubrica) {
    matchTipo = 'area_para_todos';
    rubrica = rubricas.find(r =>
      activa(r) &&
      normalizar(r.area) === area &&
      normalizar(r.mencion) === 'para todos' &&
      normalizar(r.tipoTarea) === tipoTarea
    );
  }

  if (!rubrica) {
    matchTipo = 'general_tipo_tarea';
    rubrica = rubricas.find(r =>
      activa(r) &&
      normalizar(r.area) === 'para todos' &&
      normalizar(r.mencion) === 'para todos' &&
      normalizar(r.tipoTarea) === tipoTarea
    );
  }

  if (!rubrica) {
    matchTipo = 'general_para_todos';
    rubrica = rubricas.find(r =>
      activa(r) &&
      normalizar(r.banco) === 'general para todos'
    );
  }

  if (!rubrica) {
    matchTipo = 'sin_rubrica';
    rubrica = {
      rubricaId: 'SIN-RUBRICA',
      banco: 'Fallback interno',
      area: entrega.area || '',
      mencion: entrega.mencion || '',
      tipoTarea: entrega.tipoTarea || '',
      grado: entrega.grado || '',
      rubrica:
        'No se encontró rúbrica específica. Evaluar cumplimiento de la consigna, calidad del contenido, coherencia, orden, ortografía y puntualidad sobre 60 puntos.',
    };
  }

  return { rubrica, matchTipo };
}

return entregas.map(entrega => {
  const { rubrica, matchTipo } = buscarRubrica(entrega);
  const grupoEvaluacion = crearGrupo(entrega);

  return {
    json: {
      ...entrega,

      grupoEvaluacion,
      grupoProfesor:
        entrega.teacherName ||
        entrega.docenteNombre ||
        entrega.teacherFolderName ||
        'Profesor no identificado',
      grupoCurso:
        entrega.courseName ||
        entrega.curso ||
        entrega.courseSection ||
        'Curso no identificado',
      grupoArea: entrega.area || entrega.materia || 'Area no identificada',
      grupoMencion: entrega.mencion || 'Para todos',
      grupoTarea:
        entrega.tituloTarea ||
        entrega.assignmentTitle ||
        entrega.assignmentName ||
        entrega.title ||
        'Tarea sin nombre',

      rubricaId: rubrica.rubricaId,
      rubricaSeleccionada: rubrica.rubrica,
      rubricaMatchTipo: matchTipo,
    },
  };
});

const datosBase = $('20. Merge').all().map(item => item.json);
const pruebasIA = $input.all().map(item => item.json);

function obtenerTextoIA(item) {
  return (
    item.output?.[0]?.content?.[0]?.text ||
    item.content?.[0]?.text ||
    item.text ||
    item.output_text ||
    ''
  );
}

function limpiarJson(texto) {
  return String(texto || '')
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();
}

function parsearPrueba(item) {
  const texto = limpiarJson(obtenerTextoIA(item));

  try {
    return JSON.parse(texto);
  } catch (error) {
    return {
      pruebaEstado: 'error_generacion',
      cantidadPreguntas: 0,
      tiempoTotalSegundos: 240,
      tiempoPorPreguntaSegundos: 45,
      intentosPermitidos: 1,
      preguntas: [],
      pruebaParseError: true,
      pruebaTextoOriginal: texto,
    };
  }
}

function crearId(prefix = 'quiz') {
  return `${prefix}_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
}

return datosBase.map((datos, index) => {
  const prueba = parsearPrueba(pruebasIA[index] || {});
  const quizId = crearId('quiz');

  const linkCreadoEn = new Date();
  const linkExpiraEn = new Date(linkCreadoEn.getTime() + 5 * 60 * 1000);

  const appBaseUrl = 'https://TU-APP-WEB.com/prueba';
  const quizUrl = `${appBaseUrl}/${quizId}`;

  return {
    json: {
      ...datos,

      quizId,
      quizUrl,

      pruebaEstado: 'pendiente',
      linkCreadoEn: linkCreadoEn.toISOString(),
      linkExpiraEn: linkExpiraEn.toISOString(),
      linkExpiresInSeconds: 300,

      pruebaIniciadaEn: null,
      pruebaFinalizadaEn: null,
      intentoUsado: false,

      cantidadPreguntas: prueba.cantidadPreguntas || 5,
      tiempoTotalSegundos: 240,
      tiempoPorPreguntaSegundos: 45,
      intentosPermitidos: 1,

      preguntas: prueba.preguntas || [],
      respuestasCorrectas: (prueba.preguntas || []).map(p => ({
        numero: p.numero,
        respuestaCorrecta: p.respuestaCorrecta,
      })),

      respuestasEstudiante: [],
      notaPruebaSobre40: null,
    },
  };
});

